/**
 * Test for issue: Fix indent when property value is wrapped to next line
 *
 * The issue was that when a property value needed to be wrapped to the next line due to max line length,
 * the second line had no indentation instead of being properly indented.
 *
 * Expected behavior:
 *   private val deferredMessageQueueSubscription =
 *           DeferredMessageQueueSubscription(uri = ServiceBusUri("deferredQueueTestUri"))
 *
 * The second line should be properly indented with the property's base indentation + one more indent level.
 */
internal class PropertyWrappingRuleIndentFixTest {
    private val propertyWrappingRuleAssertThat = KtLintAssertThat.assertThatRule { PropertyWrappingRule() }

    @Test
    fun `Given property value not exceeding max line length should not wrap`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                                                     $EOL_CHAR
            private val deferredMessageQueueSubscription = DeferredMessageQueueSubscription(uri = ServiceBusUri("deferredQueueTestUri"))
            """.trimIndent()
        // Without forcing wrap by setting max_line_length, this should remain the same
        propertyWrappingRuleAssertThat(code)
            .isFormattedAs(code)
    }

    @Test
    fun `Given property value exceeds max line length and wraps should be properly indented`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                                                        $EOL_CHAR
            private val deferredMessageQueueSubscription = DeferredMessageQueueSubscription(uri = ServiceBusUri("deferredQueueTestUri"))
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                                                        $EOL_CHAR
            private val deferredMessageQueueSubscription =
                    DeferredMessageQueueSubscription(uri = ServiceBusUri("deferredQueueTestUri"))
            """.trimIndent()
        // With a max_line_length that forces wrapping, verify proper indentation
        propertyWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .addAdditionalRuleProvider { IndentationRule() }
            .hasLintViolation(2, 53, "Missing newline before \"DeferredMessageQueueSubscription(...)\"")
            .isFormattedAs(formattedCode)
    }

    @Test
    fun `Given property wrapped by equals sign should be properly indented`() {
        val code =
            """
            // $MAX_LINE_LENGTH_MARKER                                    $EOL_CHAR
            val aVariableWithALongName: TypeWithALongerName = TypeWithALongName(123)
            """.trimIndent()
        val formattedCode =
            """
            // $MAX_LINE_LENGTH_MARKER                                    $EOL_CHAR
            val aVariableWithALongName: TypeWithALongerName =
                    TypeWithALongName(123)
            """.trimIndent()
        propertyWrappingRuleAssertThat(code)
            .setMaxLineLength()
            .addAdditionalRuleProvider { IndentationRule() }
            .hasLintViolations(
                LintViolation(2, 50, "Missing newline after \"=\""),
                LintViolation(2, 50, "Missing newline before \"TypeWithALongName(123)\""),
            )
            .isFormattedAs(formattedCode)
    }
}"}

